<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; Session::start();Auth::requireAdmin(); $db=Database::getInstance();$msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf()){$err='安全验证失败。';}else{$a=$_POST['action']??'';if($a==='add'){$si=$_POST['site_id']??null;$tp=$_POST['type']??'webhook';$cj=$_POST['config']??'{}';$ej=$_POST['events']??'["error"]';$ia=isset($_POST['is_active'])?1:0;$db->insert('notifications',['site_id'=>$si?(int)$si:null,'type'=>$tp,'config'=>$cj,'events'=>$ej,'is_active'=>$ia]);$msg='通知已添加。';}elseif($a==='delete'){$id=(int)($_POST['id']??0);$db->delete('notifications','id=?',[$id]);$msg='通知已删除。';}elseif($a==='toggle'){$id=(int)($_POST['id']??0);$n=$db->fetch("SELECT is_active FROM `notifications` WHERE id=?",[$id]);$db->update('notifications',['is_active'=>$n['is_active']?0:1],'id=?',[$id]);$msg='状态已更新。';}}} $notifs=$db->fetchAll("SELECT n.*,s.name as site_name FROM `notifications` n LEFT JOIN `sites` s ON n.site_id=s.id ORDER BY n.created_at DESC");$sites=$db->fetchAll("SELECT id,name FROM `sites` ORDER BY name ASC");$u=Auth::user();?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>通知设置 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>通知设置</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($u['username']);?></span></div></div><?php if($msg):?><div class="alert alert-success"><?php echo e($msg);?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?php echo e($err);?></div><?php endif;?><div class="card"><div class="card-header"><h3>添加通知</h3></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="add"><div class="form-row"><div class="form-group"><label>关联站点</label><select name="site_id"><option value="">全部站点</option><?php foreach($sites as $st):?><option value="<?php echo $st['id'];?>"><?php echo e($st['name']);?></option><?php endforeach;?></select></div><div class="form-group"><label>通知类型</label><select name="type"><option value="webhook">Webhook</option><option value="email">Email</option><option value="slack">Slack</option><option value="dingtalk">钉钉</option><option value="wechat">企业微信</option></select></div></div><div class="form-group"><label>配置 (JSON)</label><textarea name="config" rows="3">{"url": ""}</textarea></div><div class="form-group"><label>触发事件 (JSON数组)</label><input type="text" name="events" value='["error","warning"]'></div><div class="form-row form-checks"><label class="checkbox-label"><input type="checkbox" name="is_active" checked> 启用</label></div><button type="submit" class="btn btn-primary">添加通知</button></form></div></div><div class="card"><div class="card-header"><h3>通知列表 (<?php echo count($notifs);?>)</h3></div><div class="card-body"><?php if(empty($notifs)):?><p class="text-muted">暂无通知</p><?php else:?><table class="table"><thead><tr><th>站点</th><th>类型</th><th>事件</th><th>状态</th><th>操作</th></tr></thead><tbody><?php foreach($notifs as $n):?><tr><td><?php echo e($n['site_name']??'全部');?></td><td><?php echo e($n['type']);?></td><td><?php echo e($n['events']);?></td><td><span class="badge badge-<?php echo $n['is_active']?'success':'secondary';?>"><?php echo $n['is_active']?'启用':'停用';?></span></td><td class="actions"><form method="POST" style="display:inline"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?php echo $n['id'];?>"><button type="submit" class="btn-sm btn-warning"><?php echo $n['is_active']?'停用':'启用';?></button></form><form method="POST" style="display:inline" onsubmit="return confirm('确定删除？');"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?php echo $n['id'];?>"><button type="submit" class="btn-sm btn-danger">删除</button></form></td></tr><?php endforeach;?></tbody></table><?php endif;?></div></div></main></div></body></html>